#include <panic.h>
#include <printk.h>
#include <riscv.h>
#include <syscall.h>
#include <task.h>
#include <trap.h>

extern void trap_vector(void);

#define TIMER_INTERVAL 100000UL

static void timer_set_next(void)
{
    sbi_set_timer(riscv_read_time() + TIMER_INTERVAL);
}

void trap_init(void)
{
    write_stvec(trap_vector);
    printk("init: trap vector at %p\n", trap_vector);
}

void trap_enable_timer(void)
{
    write_sie(read_sie() | SIE_STIE);
    write_sstatus(read_sstatus() | SSTATUS_SIE);
    timer_set_next();
}

static const char *exception_name(u64 cause)
{
    switch (cause) {
    case 0:
        return "instruction address misaligned";
    case 1:
        return "instruction access fault";
    case 2:
        return "illegal instruction";
    case 3:
        return "breakpoint";
    case 5:
        return "load access fault";
    case 7:
        return "store/amo access fault";
    case SCAUSE_ECALL_FROM_U:
        return "ecall from user";
    case SCAUSE_ECALL_FROM_S:
        return "ecall from supervisor";
    case 12:
        return "instruction page fault";
    case 13:
        return "load page fault";
    case 15:
        return "store/amo page fault";
    default:
        return "unknown exception";
    }
}

void trap_handler(struct TrapFrame *tf)
{
    u64 scause = read_scause();
    u64 stval = read_stval();

    if ((scause & SCAUSE_INTERRUPT) != 0) {
        if ((scause & ~SCAUSE_INTERRUPT) == SCAUSE_SUPERVISOR_TIMER) {
            timer_set_next();
            task_request_resched();
            task_on_trap_return(tf);
            return;
        }
        printk("trap: interrupt scause=%x sepc=%p stval=%p\n",
               (u32)scause, (void *)tf->sepc, (void *)stval);
        return;
    }

    if (scause == SCAUSE_ECALL_FROM_U || scause == SCAUSE_ECALL_FROM_S) {
        if (tf->a7 == SYS_rt_sigreturn) {
            task_rt_sigreturn(tf);
            task_on_trap_return(tf);
            return;
        }
        {
            long ret = syscall_dispatch(tf);

            if (ret != SYS_RESTART) {
                tf->a0 = (u64)ret;
                tf->sepc += 4;
            }
        }
        task_on_trap_return(tf);
        return;
    }

    if (scause == 12 || scause == 13 || scause == 15) {
        if (task_handle_page_fault((uintptr_t)stval, scause) == 0) {
            task_on_trap_return(tf);
            return;
        }
        task_kill_current(11);
        task_on_trap_return(tf);
        return;
    }

    if (scause == 3) {
        printk("trap: user breakpoint, killing task sepc=%p\n", (void *)tf->sepc);
        task_exit_group(128 + 5);
        task_on_trap_return(tf);
        return;
    }

    printk("trap: exception %s\n", exception_name(scause));
    printk("trap: scause=%x sepc=%p stval=%p\n",
           (u32)scause, (void *)tf->sepc, (void *)stval);
    panic("unhandled trap");
}

