#define VM_PAGE_COUNT (PHYS_MEM_SIZE / PAGE_SIZE)
#define VM_NO_FREE_PAGE (-1)

struct PageInfo {
    u16 ref;
    int next;
    int on_free;
};

static pagetable_t kernel_root;
static uintptr_t early_free;
static struct PageInfo page_infos[VM_PAGE_COUNT];
static int free_page_head = VM_NO_FREE_PAGE;
static usize free_pages;
static int page_allocator_ready;

static uintptr_t align_up(uintptr_t value, uintptr_t align)
{
    return (value + align - 1) & ~(align - 1);
}

static uintptr_t align_down(uintptr_t value, uintptr_t align)
{
    return value & ~(align - 1);
}

static u64 vpn_index(uintptr_t va, int level)
{
    return (va >> (12 + 9 * level)) & 0x1ffUL;
}

static int pte_is_leaf(pte_t pte)
{
    return (pte & (PTE_R | PTE_W | PTE_X)) != 0;
}

static int pa_is_managed(uintptr_t pa)
{
    return pa >= PHYS_MEM_BASE && pa < PHYS_MEM_END &&
           (pa & (PAGE_SIZE - 1)) == 0;
}

static usize pa_to_page_index(uintptr_t pa)
{
    return (pa - PHYS_MEM_BASE) / PAGE_SIZE;
}

static uintptr_t page_index_to_pa(usize index)
{
    return PHYS_MEM_BASE + index * PAGE_SIZE;
}

static void page_list_push(usize index)
{
    if (page_infos[index].on_free) {
        panic("physical page double free");
    }
    page_infos[index].on_free = 1;
    page_infos[index].next = free_page_head;
    free_page_head = (int)index;
    free_pages++;
}

static usize page_list_pop(void)
{
    usize index;

    if (free_page_head == VM_NO_FREE_PAGE) {
        panic("physical page allocator exhausted");
    }

    index = (usize)free_page_head;
    free_page_head = page_infos[index].next;
    page_infos[index].next = VM_NO_FREE_PAGE;
    page_infos[index].on_free = 0;
    free_pages--;
    return index;
}

void vm_incref_page(uintptr_t pa)
{
    usize index;

    if (!page_allocator_ready || !pa_is_managed(pa)) {
        return;
    }

    index = pa_to_page_index(pa);
    if (page_infos[index].on_free) {
        panic("vm_incref_page on free-list page");
    }
    if (page_infos[index].ref == (u16)~0U) {
        panic("physical page reference count overflow");
    }

    page_infos[index].ref++;
}

void vm_decref_page(uintptr_t pa)
{
    usize index;

    if (!page_allocator_ready || !pa_is_managed(pa)) {
        return;
    }

    index = pa_to_page_index(pa);
    if (page_infos[index].ref == 0) {
        panic("vm_decref_page on free page");
    }

    page_infos[index].ref--;
    if (page_infos[index].ref == 0) {
        page_list_push(index);
    }
}

usize vm_page_refcount(uintptr_t pa)
{
    if (!page_allocator_ready || !pa_is_managed(pa)) {
        return 0;
    }

    return page_infos[pa_to_page_index(pa)].ref;
}

static void vm_page_allocator_init(void)
{
    usize used_pages;
    usize i;

    if (early_free == 0) {
        early_free = align_up((uintptr_t)__kernel_end, PAGE_SIZE);
    }

    used_pages = (align_up(early_free, PAGE_SIZE) - PHYS_MEM_BASE) / PAGE_SIZE;
    if (used_pages > VM_PAGE_COUNT) {
        panic("kernel uses more memory than available RAM");
    }

    free_page_head = VM_NO_FREE_PAGE;
    free_pages = 0;
    for (i = 0; i < VM_PAGE_COUNT; i++) {
        page_infos[i].next = VM_NO_FREE_PAGE;
        page_infos[i].on_free = 0;
        if (i < used_pages) {
            page_infos[i].ref = 1;
        } else {
            page_infos[i].ref = 0;
            page_list_push(i);
        }
    }

    page_allocator_ready = 1;
    printk("init: page allocator total=%d used=%d free=%d\n",
           (int)VM_PAGE_COUNT, (int)used_pages, (int)free_pages);
}

void *vm_alloc_page(void)
{
    void *page;
    usize index;

    if (page_allocator_ready) {
        index = page_list_pop();
        page_infos[index].ref = 0;
        page = (void *)page_index_to_pa(index);
        memset(page, 0, PAGE_SIZE);
        return page;
    }

    if (early_free == 0) {
        early_free = align_up((uintptr_t)__kernel_end, PAGE_SIZE);
    }

    if (early_free + PAGE_SIZE > PHYS_MEM_END) {
        panic("early page allocator exhausted");
    }

    page = (void *)early_free;
    early_free += PAGE_SIZE;
    memset(page, 0, PAGE_SIZE);
    return page;
}

void vm_free_page(void *page)
{
    uintptr_t pa = (uintptr_t)page;
    usize index;

    if (!page_allocator_ready || !pa_is_managed(pa)) {
        return;
    }

    index = pa_to_page_index(pa);
    if (page_infos[index].on_free) {
        panic("vm_free_page called on free-list page");
    }
    if (page_infos[index].ref != 0) {
        panic("vm_free_page called on referenced page");
    }

    page_list_push(index);
}

usize vm_free_page_count(void)
{
    return free_pages;
}

pagetable_t vm_kernel_pagetable(void)
{
    return kernel_root;
}

pagetable_t vm_create_user_pagetable(void)
{
    pagetable_t root = (pagetable_t)vm_alloc_page();
    vm_incref_page((uintptr_t)root);

    if (vm_map(root, UART0_BASE, UART0_BASE, PAGE_SIZE, VM_PERM_KERNEL_RW) < 0) {
        return NULL;
    }
    if (vm_map(root, VIRTIO0_BASE, VIRTIO0_BASE,
               VIRTIO0_SIZE, VM_PERM_KERNEL_RW) < 0) {
        return NULL;
    }

    if (vm_map(root, PHYS_MEM_BASE, PHYS_MEM_BASE,
               PHYS_MEM_SIZE, VM_PERM_KERNEL_RW | PTE_X) < 0) {
        return NULL;
    }

    return root;
}

static int vm_clone_user_leaf(pagetable_t dst, pte_t *pte, uintptr_t va)
{
    uintptr_t pa;
    u64 perm;

    if (pte == NULL || !(*pte & PTE_V) || !pte_is_leaf(*pte) ||
        !(*pte & PTE_U)) {
        return 0;
    }

    pa = PTE_TO_PA(*pte);
    perm = PTE_FLAGS(*pte) & (PTE_R | PTE_W | PTE_X | PTE_U | PTE_SHM);
