        /* SysV shm mappings stay shared across fork instead of becoming COW. */
    } else if (perm & PTE_W) {
        perm = (perm & ~PTE_W) | PTE_COW;
        *pte = PA_TO_PTE(pa) | perm | PTE_A | PTE_D | PTE_V;
    } else {
        perm |= PTE_FLAGS(*pte) & PTE_COW;
    }

    return vm_map(dst, va, pa, PAGE_SIZE, perm);
}

