static struct Task tasks[TASK_MAX];
static struct Task *current;
static int next_pid = 1;
static int need_resched;
static int preferred_task_pid;
static int skip_preempt_tgid;
static void (*fd_clone_hook)(struct FileDesc *fd);
static void (*fd_close_hook)(struct FileDesc *fd);

static int task_index(struct Task *task)
{
    if (task == NULL) {
        return -1;
    }
    return (int)(task - tasks);
}

static void task_init_standard_fds(struct Task *task)
{
    task->fds[0].type = FD_STDIN;
    task->fds[0].flags = 0;
    task->fds[1].type = FD_STDOUT;
    task->fds[1].flags = 1;
    task->fds[2].type = FD_STDERR;
    task->fds[2].flags = 1;
}

static void task_fix_fd_storage_pointers(struct Task *dst, const struct Task *src)
{
    int fd;

    for (fd = 0; fd < TASK_MAX_FD; fd++) {
        if (dst->fds[fd].type == FD_MEMFILE &&
            src->fds[fd].data == src->fds[fd].storage) {
            dst->fds[fd].data = dst->fds[fd].storage;
        }
    }
}

static int task_files_refcount(int files_id, const struct Task *skip)
{
    int i;
    int count = 0;

    if (files_id <= 0) {
        return 0;
    }
    for (i = 0; i < TASK_MAX; i++) {
        if (tasks[i].status != TASK_UNUSED && tasks[i].status != TASK_ZOMBIE &&
            &tasks[i] != skip && tasks[i].files_id == files_id) {
            count++;
        }
    }
    return count;
}

static u64 signal_bit(int signal)
{
    if (signal <= 0 || signal > 64) {
        return 0;
    }
    return 1UL << (signal - 1);
}

static void task_queue_signal(struct Task *task, int signal)
{
    u64 bit = signal_bit(signal);

    if (task == NULL || bit == 0) {
        return;
    }
    task->signal_pending = 1;
    task->term_signal = signal;
    task->signal_pending_mask |= bit;
}

static int task_interrupt_for_signal(struct Task *task)
{
    if (task == NULL) {
        return 0;
    }
    if (task->status == TASK_SLEEPING ||
        task->status == TASK_BLOCKED ||
        task->status == TASK_FUTEX ||
        task->status == TASK_PIPE ||
        task->status == TASK_SOCKET) {
        int was_pipe = task->status == TASK_PIPE;
        int was_socket = task->status == TASK_SOCKET;

        task->status = TASK_RUNNABLE;
        task->wake_time = 0;
        if (task->futex_addr != 0) {
            task->futex_addr = 0;
            task->futex_result = -EINTR;
        }
        if (was_pipe) {
            task->pipe_wait_id = -1;
            task->pipe_wait_write = 0;
            task->restart_syscall = 0;
            task->tf.sepc += 4;
        }
        if (was_socket) {
            task->socket_wait_id = -1;
            task->socket_wait_accept = 0;
            task->restart_syscall = 0;
            task->tf.sepc += 4;
        }
        task->tf.a0 = (u64)(long)-EINTR;
        return 1;
    }
    return 0;
}

static void task_write_user_int(struct Task *task, int *user_ptr, int value)
{
    uintptr_t pa;

    if (task == NULL || user_ptr == NULL) {
        return;
    }

    pa = vm_translate(task->pagetable, (uintptr_t)user_ptr);
    if (pa == 0) {
        return;
    }

    *(int *)pa = value;
}

static int task_copy_to_user(struct Task *task, uintptr_t dst,
                             const void *src, usize len)
{
    const u8 *in = (const u8 *)src;
    usize i;

    if (task == NULL || src == NULL) {
        return -EINVAL;
    }
    for (i = 0; i < len; i++) {
        uintptr_t pa = vm_translate(task->pagetable, dst + i);

        if (pa == 0) {
            if (task_handle_page_fault(dst + i, 15) < 0) {
                return -EINVAL;
            }
            pa = vm_translate(task->pagetable, dst + i);
            if (pa == 0) {
                return -EINVAL;
            }
        }
        *(u8 *)pa = in[i];
    }
    return 0;
}

static int task_copy_from_user(struct Task *task, void *dst,
                               uintptr_t src, usize len)
{
    u8 *out = (u8 *)dst;
    usize i;

    if (task == NULL || dst == NULL) {
        return -EINVAL;
    }
    for (i = 0; i < len; i++) {
        uintptr_t pa = vm_translate(task->pagetable, src + i);

        if (pa == 0) {
            return -EINVAL;
        }
        out[i] = *(u8 *)pa;
    }
    return 0;
}

