static void task_save_regs(struct UserRegs *regs, const struct TrapFrame *tf)
{
    regs->pc = tf->sepc;
    regs->ra = tf->ra;
    regs->sp = tf->sp;
    regs->gp = tf->gp;
    regs->tp = tf->tp;
    regs->t0 = tf->t0;
