    envc = copy_user_vec((const char *const *)tf->a2, envp_storage, envp, EXEC_MAX_ENVC);
    if (envc < 0) {
        return envc;
    }
    if (argc == 0) {
        argv[0] = path_storage;
        argc = 1;
    }

    for (i = 0; i < argc; i++) {
        final_argv[i] = argv[i];
    }
    final_argc = argc;
    for (i = 0; i < envc; i++) {
        final_envp[i] = envp[i];
    }

    fs_resolve_task_path(task, path_storage, resolved_path, sizeof(resolved_path));
    ret = fs_read_all(resolved_path, &image, &image_size);
    if (ret < 0) {
        return ret;
    }
    if (image == NULL || image_size == 0) {
        return -EINVAL;
    }

    shebang_interp[0] = '\0';
    shebang_arg[0] = '\0';
    if (image_size >= 2 && ((const char *)image)[0] == '#' &&
        ((const char *)image)[1] == '!' &&
        split_shebang((const char *)image, shebang_interp, shebang_arg)) {
        int out = 0;

        final_argv[out++] = shebang_interp;
        if (shebang_arg[0] != '\0' && out < EXEC_MAX_ARGC) {
            final_argv[out++] = shebang_arg;
        }
        if (out < EXEC_MAX_ARGC) {
            final_argv[out++] = resolved_path;
        }
        for (i = 1; i < argc && out < EXEC_MAX_ARGC; i++) {
            final_argv[out++] = argv[i];
        }
        if (i < argc) {
            return -EINVAL;
        }
        final_argc = out;

        ret = fs_read_all(resolve_path_arg(task, shebang_interp,
                                           resolved_interp, sizeof(resolved_interp)),
                          &image, &image_size);
        if (ret < 0) {
            return ret;
        }
        if (image == NULL || image_size == 0) {
            return -EINVAL;
        }
    }

    ret = copy_exec_image(image, image_size, exec_main_image_buf,
                          &image, &image_size);
    if (ret < 0) {
        return ret;
    }

    ret = elf_get_interp(image, image_size, interp_path, sizeof(interp_path));
    if (ret < 0) {
        return ret;
    }
    if (ret > 0 && !elf_interp_is_optional(image, image_size)) {
        ret = read_dynamic_interp(task, resolved_path, interp_path,
                                  resolved_interp, sizeof(resolved_interp),
                                  &interp_image, &interp_image_size);
        if (ret < 0) {
            printk("execve: missing dynamic ELF interpreter %s\n", interp_path);
            return ret;
        }
        if (interp_image == NULL || interp_image_size == 0) {
            return -EINVAL;
        }
        ret = copy_exec_image(interp_image, interp_image_size, exec_interp_image_buf,
                              &interp_image, &interp_image_size);
        if (ret < 0) {
            return ret;
        }
    }

    vm_unmap(task->pagetable, USER_BASE, USER_HEAP_LIMIT - USER_BASE);
    if (task->mmap_next > USER_MMAP_BASE) {
        vm_unmap(task->pagetable, USER_MMAP_BASE, task->mmap_next - USER_MMAP_BASE);
    }
    vm_unmap(task->pagetable, USER_STACK_TOP - USER_STACK_SIZE, USER_STACK_SIZE);
    ret = elf_load_into_at(task->pagetable, image, image_size,
                           EXEC_MAIN_DYN_BASE, &main_info);
    if (ret < 0) {
        return ret;
    }
    if (interp_image != NULL) {
        ret = elf_load_into_at(task->pagetable, interp_image, interp_image_size,
                               EXEC_INTERP_BASE, &interp_info);
        if (ret < 0) {
            return ret;
        }
        entry = (void (*)(void))interp_info.entry;
    } else {
        memset(&interp_info, 0, sizeof(interp_info));
        entry = (void (*)(void))main_info.entry;
    }

    auxv[auxc++] = (struct UserAuxv){ AT_PHDR, main_info.phdr };
    auxv[auxc++] = (struct UserAuxv){ AT_PHENT, main_info.phent };
    auxv[auxc++] = (struct UserAuxv){ AT_PHNUM, main_info.phnum };
    auxv[auxc++] = (struct UserAuxv){ AT_BASE, interp_image != NULL ? interp_info.bias : 0 };
    auxv[auxc++] = (struct UserAuxv){ AT_FLAGS, 0 };
    auxv[auxc++] = (struct UserAuxv){ AT_ENTRY, main_info.entry };

    stack = user_stack_prepare_args_aux_on(task->pagetable,
                                           final_argv, final_argc,
                                           final_envp, envc,
                                           auxv, auxc);
    if (stack == NULL) {
        return -ENOMEM;
    }

    close_cloexec_fds(task);

    task->sigaltstack_sp = 0;
    task->sigaltstack_size = 0;
    task->sigaltstack_flags = SS_DISABLE;

    brk_start = main_info.loaded_end;
    if (interp_info.loaded_end > brk_start) {
        brk_start = interp_info.loaded_end;
    }
    task->brk_start = brk_start;
    task->brk_current = brk_start;
    task->brk_limit = USER_HEAP_LIMIT;
    task->mmap_next = USER_MMAP_BASE;
    task->mmap_limit = USER_MMAP_LIMIT;

    /*
     * trap_handler advances sepc by 4 after syscall_dispatch returns.
     * Store entry - 4 so the final return target is the new ELF entry.
     */
    tf->sepc = (u64)(uintptr_t)entry - 4;
    tf->sp = (u64)(uintptr_t)stack;
    return 0;
}

