#include <block.h>
#include <memlayout.h>
#include <printk.h>
#include <string.h>
#include <types.h>

#define VIRTIO_MMIO_MAGIC_VALUE        0x000
#define VIRTIO_MMIO_VERSION            0x004
#define VIRTIO_MMIO_DEVICE_ID          0x008
#define VIRTIO_MMIO_DEVICE_FEATURES    0x010
#define VIRTIO_MMIO_DRIVER_FEATURES    0x020
#define VIRTIO_MMIO_GUEST_PAGE_SIZE    0x028
#define VIRTIO_MMIO_QUEUE_SEL          0x030
#define VIRTIO_MMIO_QUEUE_NUM_MAX      0x034
#define VIRTIO_MMIO_QUEUE_NUM          0x038
#define VIRTIO_MMIO_QUEUE_ALIGN        0x03c
#define VIRTIO_MMIO_QUEUE_PFN          0x040
#define VIRTIO_MMIO_QUEUE_READY        0x044
#define VIRTIO_MMIO_QUEUE_NOTIFY       0x050
#define VIRTIO_MMIO_INTERRUPT_STATUS   0x060
#define VIRTIO_MMIO_INTERRUPT_ACK      0x064
#define VIRTIO_MMIO_STATUS             0x070
#define VIRTIO_MMIO_QUEUE_DESC_LOW     0x080
#define VIRTIO_MMIO_QUEUE_DESC_HIGH    0x084
#define VIRTIO_MMIO_QUEUE_AVAIL_LOW    0x090
#define VIRTIO_MMIO_QUEUE_AVAIL_HIGH   0x094
#define VIRTIO_MMIO_QUEUE_USED_LOW     0x0a0
#define VIRTIO_MMIO_QUEUE_USED_HIGH    0x0a4

#define VIRTIO_STATUS_ACKNOWLEDGE 1
#define VIRTIO_STATUS_DRIVER      2
#define VIRTIO_STATUS_DRIVER_OK   4
#define VIRTIO_STATUS_FEATURES_OK 8
#define VIRTIO_STATUS_FAILED      128

#define VIRTQ_DESC_F_NEXT  1
#define VIRTQ_DESC_F_WRITE 2

#define VIRTIO_BLK_T_IN 0
#define VIRTQ_SIZE 8

struct VirtqDesc {
    u64 addr;
    u32 len;
    u16 flags;
    u16 next;
};

struct VirtqAvail {
    u16 flags;
    u16 idx;
    u16 ring[VIRTQ_SIZE];
};

struct VirtqUsedElem {
    u32 id;
    u32 len;
};

struct VirtqUsed {
    u16 flags;
    u16 idx;
    struct VirtqUsedElem ring[VIRTQ_SIZE];
};

struct VirtioBlkReq {
    u32 type;
    u32 reserved;
    u64 sector;
};

static u8 queue_mem[8192] __attribute__((aligned(4096)));
static volatile struct VirtqDesc *virtq_desc;
static volatile struct VirtqAvail *virtq_avail;
static volatile struct VirtqUsed *virtq_used;
static struct VirtioBlkReq blk_req __attribute__((aligned(16)));
static volatile u8 blk_status __attribute__((aligned(1)));
static int blk_ready;
static u16 used_seen;

static volatile u32 *mmio_reg(u32 offset)
{
    return (volatile u32 *)(VIRTIO0_BASE + offset);
}

static u32 mmio_read(u32 offset)
{
    return *mmio_reg(offset);
}

static void mmio_write(u32 offset, u32 value)
{
    *mmio_reg(offset) = value;
}

static void mem_barrier(void)
{
    __asm__ volatile ("fence rw, rw" ::: "memory");
}

void block_init(void)
{
    u32 magic = mmio_read(VIRTIO_MMIO_MAGIC_VALUE);
    u32 version = mmio_read(VIRTIO_MMIO_VERSION);
    u32 device = mmio_read(VIRTIO_MMIO_DEVICE_ID);
    u32 qmax;
    uintptr_t addr;

    blk_ready = 0;
    if (magic != 0x74726976 || (version != 1 && version != 2) || device != 2) {
        printk("init: virtio-blk not found magic=%x version=%d device=%d\n",
               magic, version, device);
        return;
    }

    mmio_write(VIRTIO_MMIO_STATUS, 0);
    mmio_write(VIRTIO_MMIO_STATUS, VIRTIO_STATUS_ACKNOWLEDGE);
    mmio_write(VIRTIO_MMIO_STATUS,
               VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER);

    (void)mmio_read(VIRTIO_MMIO_DEVICE_FEATURES);
    mmio_write(VIRTIO_MMIO_DRIVER_FEATURES, 0);
    if (version == 2) {
        mmio_write(VIRTIO_MMIO_STATUS,
                   VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER |
                   VIRTIO_STATUS_FEATURES_OK);
        if ((mmio_read(VIRTIO_MMIO_STATUS) & VIRTIO_STATUS_FEATURES_OK) == 0) {
            mmio_write(VIRTIO_MMIO_STATUS, VIRTIO_STATUS_FAILED);
            printk("init: virtio-blk feature negotiation failed\n");
            return;
        }
    }

    mmio_write(VIRTIO_MMIO_QUEUE_SEL, 0);
    qmax = mmio_read(VIRTIO_MMIO_QUEUE_NUM_MAX);
    if (qmax < VIRTQ_SIZE) {
        printk("init: virtio-blk queue too small max=%d\n", qmax);
        return;
    }

    memset(queue_mem, 0, sizeof(queue_mem));
    virtq_desc = (struct VirtqDesc *)queue_mem;
    virtq_avail = (struct VirtqAvail *)(queue_mem + sizeof(struct VirtqDesc) * VIRTQ_SIZE);
    virtq_used = (struct VirtqUsed *)(queue_mem + 4096);

    mmio_write(VIRTIO_MMIO_QUEUE_NUM, VIRTQ_SIZE);
    if (version == 1) {
        mmio_write(VIRTIO_MMIO_GUEST_PAGE_SIZE, PAGE_SIZE);
        mmio_write(VIRTIO_MMIO_QUEUE_ALIGN, PAGE_SIZE);
        mmio_write(VIRTIO_MMIO_QUEUE_PFN, (u32)((uintptr_t)queue_mem >> 12));
    } else {
        addr = (uintptr_t)virtq_desc;
        mmio_write(VIRTIO_MMIO_QUEUE_DESC_LOW, (u32)addr);
        mmio_write(VIRTIO_MMIO_QUEUE_DESC_HIGH, (u32)(addr >> 32));
        addr = (uintptr_t)virtq_avail;
        mmio_write(VIRTIO_MMIO_QUEUE_AVAIL_LOW, (u32)addr);
        mmio_write(VIRTIO_MMIO_QUEUE_AVAIL_HIGH, (u32)(addr >> 32));
        addr = (uintptr_t)virtq_used;
        mmio_write(VIRTIO_MMIO_QUEUE_USED_LOW, (u32)addr);
        mmio_write(VIRTIO_MMIO_QUEUE_USED_HIGH, (u32)(addr >> 32));
        mmio_write(VIRTIO_MMIO_QUEUE_READY, 1);
    }

    used_seen = 0;
    mmio_write(VIRTIO_MMIO_STATUS,
               VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER |
               VIRTIO_STATUS_FEATURES_OK | VIRTIO_STATUS_DRIVER_OK);
    blk_ready = 1;
    printk("init: virtio-blk ready version=%d\n", version);
}

int block_available(void)
{
    return blk_ready;
}

int block_read_sector(u64 sector, void *buf)
{
    int attempt;

    if (!blk_ready || buf == NULL) {
        return -1;
    }

    for (attempt = 0; attempt < 4; attempt++) {
        blk_req.type = VIRTIO_BLK_T_IN;
        blk_req.reserved = 0;
        blk_req.sector = sector;
        blk_status = 0xff;

        virtq_desc[0].addr = (u64)(uintptr_t)&blk_req;
        virtq_desc[0].len = sizeof(blk_req);
        virtq_desc[0].flags = VIRTQ_DESC_F_NEXT;
        virtq_desc[0].next = 1;

        virtq_desc[1].addr = (u64)(uintptr_t)buf;
        virtq_desc[1].len = BLOCK_SECTOR_SIZE;
        virtq_desc[1].flags = VIRTQ_DESC_F_WRITE | VIRTQ_DESC_F_NEXT;
        virtq_desc[1].next = 2;

        virtq_desc[2].addr = (u64)(uintptr_t)&blk_status;
        virtq_desc[2].len = sizeof(blk_status);
        virtq_desc[2].flags = VIRTQ_DESC_F_WRITE;
        virtq_desc[2].next = 0;

        virtq_avail->ring[virtq_avail->idx % VIRTQ_SIZE] = 0;
        mem_barrier();
        virtq_avail->idx++;
        mem_barrier();

        mmio_write(VIRTIO_MMIO_QUEUE_NOTIFY, 0);
        while (used_seen == virtq_used->idx) {
            mem_barrier();
        }
        mem_barrier();
        used_seen++;

        if (mmio_read(VIRTIO_MMIO_INTERRUPT_STATUS) != 0) {
            mmio_write(VIRTIO_MMIO_INTERRUPT_ACK,
                       mmio_read(VIRTIO_MMIO_INTERRUPT_STATUS));
        }
        if (blk_status == 0) {
            return 0;
        }
    }

    return -1;
}

#include <memlayout.h>
#include <net.h>
#include <printk.h>
#include <string.h>
#include <types.h>

#define VIRTIO_MMIO_MAGIC_VALUE        0x000
#define VIRTIO_MMIO_VERSION            0x004
#define VIRTIO_MMIO_DEVICE_ID          0x008
#define VIRTIO_MMIO_DEVICE_FEATURES    0x010
#define VIRTIO_MMIO_DRIVER_FEATURES    0x020
#define VIRTIO_MMIO_GUEST_PAGE_SIZE    0x028
#define VIRTIO_MMIO_QUEUE_SEL          0x030
#define VIRTIO_MMIO_QUEUE_NUM_MAX      0x034
#define VIRTIO_MMIO_QUEUE_NUM          0x038
#define VIRTIO_MMIO_QUEUE_ALIGN        0x03c
#define VIRTIO_MMIO_QUEUE_PFN          0x040
#define VIRTIO_MMIO_QUEUE_READY        0x044
#define VIRTIO_MMIO_QUEUE_NOTIFY       0x050
#define VIRTIO_MMIO_INTERRUPT_STATUS   0x060
#define VIRTIO_MMIO_INTERRUPT_ACK      0x064
#define VIRTIO_MMIO_STATUS             0x070
#define VIRTIO_MMIO_QUEUE_DESC_LOW     0x080
#define VIRTIO_MMIO_QUEUE_DESC_HIGH    0x084
#define VIRTIO_MMIO_QUEUE_AVAIL_LOW    0x090
#define VIRTIO_MMIO_QUEUE_AVAIL_HIGH   0x094
#define VIRTIO_MMIO_QUEUE_USED_LOW     0x0a0
#define VIRTIO_MMIO_QUEUE_USED_HIGH    0x0a4

#define VIRTIO_STATUS_ACKNOWLEDGE 1
#define VIRTIO_STATUS_DRIVER      2
#define VIRTIO_STATUS_DRIVER_OK   4
#define VIRTIO_STATUS_FEATURES_OK 8
#define VIRTIO_STATUS_FAILED      128

#define VIRTQ_DESC_F_NEXT  1
#define VIRTQ_DESC_F_WRITE 2

#define VIRTQ_SIZE 8
#define RX_QUEUE 0
#define TX_QUEUE 1
#define VIRTIO_NET_HDR_SIZE 12

struct VirtqDesc {
    u64 addr;
    u32 len;
    u16 flags;
    u16 next;
};

struct VirtqAvail {
    u16 flags;
    u16 idx;
    u16 ring[VIRTQ_SIZE];
};

struct VirtqUsedElem {
    u32 id;
    u32 len;
};

struct VirtqUsed {
    u16 flags;
    u16 idx;
    struct VirtqUsedElem ring[VIRTQ_SIZE];
};

struct NetQueue {
    u8 mem[8192] __attribute__((aligned(4096)));
    volatile struct VirtqDesc *desc;
    volatile struct VirtqAvail *avail;
    volatile struct VirtqUsed *used;
    u16 used_seen;
};

static struct NetQueue rxq;
static struct NetQueue txq;
static u8 rx_buf[VIRTQ_SIZE][VIRTIO_NET_HDR_SIZE + NET_MTU] __attribute__((aligned(16)));
static u8 tx_buf[VIRTIO_NET_HDR_SIZE + NET_MTU] __attribute__((aligned(16)));
static uintptr_t net_base = VIRTIO1_BASE;
static int net_ready;

static volatile u32 *net_reg(u32 offset)
{
    return (volatile u32 *)(net_base + offset);
}

static u32 net_read(u32 offset)
{
    return *net_reg(offset);
}

static void net_write(u32 offset, u32 value)
{
    *net_reg(offset) = value;
}

static void net_barrier(void)
{
    __asm__ volatile ("fence rw, rw" ::: "memory");
}

static void queue_layout(struct NetQueue *q)
{
    q->desc = (struct VirtqDesc *)q->mem;
    q->avail = (struct VirtqAvail *)(q->mem + sizeof(struct VirtqDesc) * VIRTQ_SIZE);
    q->used = (struct VirtqUsed *)(q->mem + 4096);
    q->used_seen = 0;
}

static int queue_setup(struct NetQueue *q, u32 index, u32 version)
{
    u32 qmax;
    uintptr_t addr;

    net_write(VIRTIO_MMIO_QUEUE_SEL, index);
    qmax = net_read(VIRTIO_MMIO_QUEUE_NUM_MAX);
    if (qmax < VIRTQ_SIZE) {
        return -1;
    }

    memset(q->mem, 0, sizeof(q->mem));
    queue_layout(q);
    net_write(VIRTIO_MMIO_QUEUE_NUM, VIRTQ_SIZE);
    if (version == 1) {
        net_write(VIRTIO_MMIO_GUEST_PAGE_SIZE, PAGE_SIZE);
        net_write(VIRTIO_MMIO_QUEUE_ALIGN, PAGE_SIZE);
        net_write(VIRTIO_MMIO_QUEUE_PFN, (u32)((uintptr_t)q->mem >> 12));
    } else {
        addr = (uintptr_t)q->desc;
        net_write(VIRTIO_MMIO_QUEUE_DESC_LOW, (u32)addr);
        net_write(VIRTIO_MMIO_QUEUE_DESC_HIGH, (u32)(addr >> 32));
        addr = (uintptr_t)q->avail;
        net_write(VIRTIO_MMIO_QUEUE_AVAIL_LOW, (u32)addr);
        net_write(VIRTIO_MMIO_QUEUE_AVAIL_HIGH, (u32)(addr >> 32));
        addr = (uintptr_t)q->used;
        net_write(VIRTIO_MMIO_QUEUE_USED_LOW, (u32)addr);
        net_write(VIRTIO_MMIO_QUEUE_USED_HIGH, (u32)(addr >> 32));
        net_write(VIRTIO_MMIO_QUEUE_READY, 1);
    }
    return 0;
}

static void rx_refill_one(int i)
{
    rxq.desc[i].addr = (u64)(uintptr_t)rx_buf[i];
    rxq.desc[i].len = sizeof(rx_buf[i]);
    rxq.desc[i].flags = VIRTQ_DESC_F_WRITE;
    rxq.desc[i].next = 0;
    rxq.avail->ring[rxq.avail->idx % VIRTQ_SIZE] = (u16)i;
    net_barrier();
    rxq.avail->idx++;
    net_barrier();
}

void net_init(void)
{
    u32 magic;
    u32 version;
    u32 device;
    uintptr_t base;
    int found = 0;
    int i;

    net_ready = 0;
    for (base = VIRTIO0_BASE; base < VIRTIO0_BASE + VIRTIO0_SIZE;
         base += 0x1000) {
        net_base = base;
        magic = net_read(VIRTIO_MMIO_MAGIC_VALUE);
        version = net_read(VIRTIO_MMIO_VERSION);
        device = net_read(VIRTIO_MMIO_DEVICE_ID);
        if (magic == 0x74726976 && (version == 1 || version == 2) &&
            device == 1) {
            found = 1;
            break;
        }
    }
    if (!found) {
        printk("init: virtio-net not found\n");
        return;
    }

    net_write(VIRTIO_MMIO_STATUS, 0);
    net_write(VIRTIO_MMIO_STATUS, VIRTIO_STATUS_ACKNOWLEDGE);
    net_write(VIRTIO_MMIO_STATUS,
              VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER);
    (void)net_read(VIRTIO_MMIO_DEVICE_FEATURES);
    net_write(VIRTIO_MMIO_DRIVER_FEATURES, 0);
    if (version == 2) {
        net_write(VIRTIO_MMIO_STATUS,
                  VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER |
                  VIRTIO_STATUS_FEATURES_OK);
        if ((net_read(VIRTIO_MMIO_STATUS) & VIRTIO_STATUS_FEATURES_OK) == 0) {
            net_write(VIRTIO_MMIO_STATUS, VIRTIO_STATUS_FAILED);
            printk("init: virtio-net feature negotiation failed\n");
            return;
        }
    }

    if (queue_setup(&rxq, RX_QUEUE, version) < 0 ||
        queue_setup(&txq, TX_QUEUE, version) < 0) {
        net_write(VIRTIO_MMIO_STATUS, VIRTIO_STATUS_FAILED);
        printk("init: virtio-net queue setup failed\n");
        return;
    }
    for (i = 0; i < VIRTQ_SIZE; i++) {
        rx_refill_one(i);
    }
    net_write(VIRTIO_MMIO_QUEUE_NOTIFY, RX_QUEUE);
    net_write(VIRTIO_MMIO_STATUS,
              VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER |
              VIRTIO_STATUS_FEATURES_OK | VIRTIO_STATUS_DRIVER_OK);
    net_ready = 1;
    printk("init: virtio-net ready base=%p version=%d\n",
           (void *)net_base, version);
}

int net_available(void)
{
    return net_ready;
}

int net_send_packet(const void *data, usize len)
{
    if (!net_ready || data == NULL || len > NET_MTU) {
        return -1;
    }
    memset(tx_buf, 0, VIRTIO_NET_HDR_SIZE);
    memcpy(tx_buf + VIRTIO_NET_HDR_SIZE, data, len);

    txq.desc[0].addr = (u64)(uintptr_t)tx_buf;
    txq.desc[0].len = (u32)(VIRTIO_NET_HDR_SIZE + len);
    txq.desc[0].flags = 0;
    txq.desc[0].next = 0;
    txq.avail->ring[txq.avail->idx % VIRTQ_SIZE] = 0;
    net_barrier();
    txq.avail->idx++;
    net_barrier();
    net_write(VIRTIO_MMIO_QUEUE_NOTIFY, TX_QUEUE);

    while (txq.used_seen == txq.used->idx) {
        net_barrier();
    }
    txq.used_seen++;
    if (net_read(VIRTIO_MMIO_INTERRUPT_STATUS) != 0) {
        net_write(VIRTIO_MMIO_INTERRUPT_ACK,
                  net_read(VIRTIO_MMIO_INTERRUPT_STATUS));
    }
    return (int)len;
}

int net_recv_packet(void *data, usize cap)
{
    u32 id;
    u32 len;
    usize payload_len;

    if (!net_ready || data == NULL || cap == 0) {
        return -1;
    }
    if (rxq.used_seen == rxq.used->idx) {
        return 0;
    }

    id = rxq.used->ring[rxq.used_seen % VIRTQ_SIZE].id;
    len = rxq.used->ring[rxq.used_seen % VIRTQ_SIZE].len;
    rxq.used_seen++;
    if (id >= VIRTQ_SIZE || len <= VIRTIO_NET_HDR_SIZE) {
        return 0;
    }
    payload_len = len - VIRTIO_NET_HDR_SIZE;
    if (payload_len > cap) {
        payload_len = cap;
    }
    memcpy(data, rx_buf[id] + VIRTIO_NET_HDR_SIZE, payload_len);
    rx_refill_one((int)id);
    net_write(VIRTIO_MMIO_QUEUE_NOTIFY, RX_QUEUE);
    return (int)payload_len;
}

