static void print_unsigned(u64 value, u32 base)
{
    char buf[32];
    const char *digits = "0123456789abcdef";
    u32 pos = 0;

    if (value == 0) {
        uart_putc('0');
        return;
    }

    while (value != 0) {
        buf[pos++] = digits[value % base];
        value /= base;
    }

    while (pos > 0) {
        uart_putc(buf[--pos]);
    }
}

static void print_signed(long value)
{
    if (value < 0) {
        uart_putc('-');
        print_unsigned((u64)(-value), 10);
        return;
    }

    print_unsigned((u64)value, 10);
}

void vprintk(const char *fmt, va_list ap)
{
    while (*fmt != '\0') {
        if (*fmt != '%') {
            uart_putc(*fmt++);
            continue;
        }

        fmt++;
        switch (*fmt) {
        case '%':
            uart_putc('%');
            break;
        case 'c':
            uart_putc((char)va_arg(ap, int));
            break;
        case 's': {
            const char *s = va_arg(ap, const char *);
            uart_puts(s == NULL ? "(null)" : s);
            break;
        }
        case 'd':
            print_signed((long)va_arg(ap, int));
