static void scan_inode_and_skip(u32 ino, int depth, int *found,
                                char seen[][64], int *seen_count)
{
    usize pos = 0;
    struct Ext4Dirent dirent;

    if (depth > 4) {
        return;
    }
    while (ext4_getdents(ino, &pos, &dirent) > 0) {
        if (is_dot_entry(dirent.name)) {
            continue;
        }
        if (!dirent.is_dir && ends_with(dirent.name, "_testcode.sh")) {
            if (name_seen(seen, *seen_count, dirent.name)) {
                continue;
            }
            if (*seen_count < 32) {
                copy_name(seen[(*seen_count)++], dirent.name, sizeof(seen[0]));
            }
            skip_script(dirent.name);
            *found = 1;
        } else if (dirent.is_dir) {
            scan_inode_and_skip(dirent.inode, depth + 1, found,
                                seen, seen_count);
        }
    }
}

static void scan_and_skip_scripts(void)
{
    u32 root;
    int found = 0;
    char seen[32][64];
    int seen_count = 0;

    block_init();
    ext4_init();
    if (!ext4_available() || ext4_lookup_path("/", &root) < 0) {
        puts("init: no readable ext4 test disk\n");
        return;
    }

    scan_inode_and_skip(root, 0, &found, seen, &seen_count);
    if (!found) {
        puts("init: no test scripts found\n");
    }
}

