    if (table == NULL) {
        return;
    }

    for (i = 0; i < 512; i++) {
        pte_t pte = table[i];

        if (!(pte & PTE_V)) {
            continue;
        }

        if (pte_is_leaf(pte)) {
            if (pte & PTE_U) {
                vm_decref_page(PTE_TO_PA(pte));
            }
            table[i] = 0;
            continue;
        }

        if (level > 0) {
            pagetable_t child = (pagetable_t)(uintptr_t)PTE_TO_PA(pte);

            vm_free_pagetable_pages(child, level - 1);
            vm_decref_page((uintptr_t)child);
            table[i] = 0;
        }
    }
}

