    vm_decref_page((uintptr_t)root);
    sfence_vma();
}

pte_t *vm_walk(pagetable_t root, uintptr_t va, int alloc)
{
    pagetable_t table = root;
    int level;

    for (level = 2; level > 0; level--) {
        pte_t *pte = &table[vpn_index(va, level)];

        if (*pte & PTE_V) {
            if (pte_is_leaf(*pte)) {
                return NULL;
            }
            table = (pagetable_t)(uintptr_t)PTE_TO_PA(*pte);
            continue;
        }

        if (!alloc) {
            return NULL;
        }

        table = (pagetable_t)vm_alloc_page();
        vm_incref_page((uintptr_t)table);
        *pte = PA_TO_PTE((uintptr_t)table) | PTE_V;
    }

    return &table[vpn_index(va, 0)];
}

