        pte_t *pte = vm_walk(root, cur, 0);
        uintptr_t pa;
        u64 old_flags;

        if (pte == NULL || !(*pte & PTE_V) || !pte_is_leaf(*pte) ||
            !(*pte & PTE_U)) {
