void task_init(void)
{
    struct Task *init;

    memset(tasks, 0, sizeof(tasks));
    init = task_alloc_slot();
    if (init == NULL) {
        return;
    }

    init->ppid = 0;
    init->pagetable = vm_kernel_pagetable();
    init->status = TASK_RUNNING;
    init->mmap_next = USER_MMAP_BASE;
    init->mmap_limit = USER_MMAP_LIMIT;
    init->cwd[0] = '/';
    init->cwd[1] = '\0';
