static long sys_nanosleep(u64 req, u64 rem, u64 a2 unused,
                          u64 a3 unused, u64 a4 unused, u64 a5 unused)
{
    const struct TimeSpec *time = (const struct TimeSpec *)req;
    u64 sleep_ticks;

    if (time == NULL) {
        return -EINVAL;
    }

    sleep_ticks = time->sec * QEMU_VIRT_TIMEBASE +
                  ((u64)time->nsec * QEMU_VIRT_TIMEBASE) / 1000000000UL;
    if (rem != 0) {
        struct TimeSpec *remaining = (struct TimeSpec *)rem;
        remaining->sec = 0;
        remaining->nsec = 0;
    }

    if (sleep_ticks != 0) {
        task_sleep_until(read_time() + sleep_ticks);
    }

    return 0;
}

