    struct Task *task = current_task();
    u64 *mask = (u64 *)mask_ptr;

    if (task == NULL || mask == NULL ||
        !user_range_ok((uintptr_t)mask, sizeof(u64), 0)) {
        return -EFAULT;
    }
    task->signal_mask = *mask;
    task_request_resched();
    return -EINTR;
}

long syscall_dispatch(struct TrapFrame *tf)
{
    u64 sysno = tf->a7;
    const struct SyscallDesc *desc;

    if (sysno >= SYS_MAX) {
        printk("syscall: unknown id=%d\n", (int)sysno);
        return -ENOSYS;
    }

    if (sysno == SYS_clone) {
        return task_clone_current(tf, (uintptr_t)tf->a1);
    }
    if (sysno == SYS_vfork) {
        return sys_vfork_from_tf(tf);
    }
    if (sysno == SYS_clone3) {
        return sys_clone3_from_tf(tf);
    }
    if (sysno == SYS_execve) {
        return sys_execve_from_tf(tf);
    }

    desc = &syscall_table[sysno];
    if (desc->fn == NULL) {
        printk("syscall: unsupported id=%d\n", (int)sysno);
        return -ENOSYS;
    }

    return desc->fn(tf->a0, tf->a1, tf->a2, tf->a3, tf->a4, tf->a5);
}

static void strip_quotes(char *s)
{
    unsigned long len = strlen(s);

    if (len >= 2 &&
        ((s[0] == '"' && s[len - 1] == '"') ||
         (s[0] == '\'' && s[len - 1] == '\''))) {
        unsigned long i;

        for (i = 1; i < len - 1; i++) {
            s[i - 1] = s[i];
        }
        s[len - 2] = '\0';
    }
}

static int split_words(char *line, char *argv[], int max_argc)
{
    int argc = 0;
    char quote = 0;
    char *p = line;

    while (*p != '\0' && argc < max_argc - 1) {
        while (*p == ' ' || *p == '\t') {
            *p++ = '\0';
        }
        if (*p == '\0') {
            break;
        }
        argv[argc++] = p;
        while (*p != '\0') {
            if (quote != 0) {
                if (*p == quote) {
                    quote = 0;
                }
            } else if (*p == '\'' || *p == '"') {
                quote = *p;
            } else if (*p == ' ' || *p == '\t') {
                break;
            }
            p++;
        }
    }
    argv[argc] = 0;
    return argc;
}

static int is_env_assignment(const char *s)
{
    unsigned long i;

    if (s == 0 || s[0] == '\0' || s[0] == '=') {
        return 0;
    }
    for (i = 0; s[i] != '\0'; i++) {
        if (s[i] == '=') {
            return 1;
        }
        if (s[i] == '/') {
            return 0;
        }
    }
    return 0;
}

static int prepare_exec_args(char *argv[], int argc, const char *envp[], int env_cap)
{
    int i;
    int env_count = 3;

    envp[0] = "PATH=.:/bin:/";
    envp[1] = "LANG=C.UTF-8";
    envp[2] = "LC_ALL=C.UTF-8";
    envp[3] = 0;

    while (argc > 0 && is_env_assignment(argv[0])) {
        if (env_count + 1 < env_cap) {
            envp[env_count++] = argv[0];
            envp[env_count] = 0;
        }
        for (i = 0; i < argc; i++) {
            argv[i] = argv[i + 1];
        }
        argc--;
    }
    return argc;
}

static long read_all(const char *path, char *buf, unsigned long cap)
{
    long fd = syscall4(SYS_openat, AT_FDCWD, (long)path, O_RDONLY, 0);
    long total = 0;

    if (fd < 0) {
        return fd;
    }
    while ((unsigned long)total + 1 < cap) {
        unsigned long want = cap - total - 1;
        long n;

        if (want > 256) {
            want = 256;
        }
        n = syscall3(SYS_read, fd, (long)(buf + total), want);
        if (n <= 0) {
            break;
        }
        total += n;
    }
    buf[total] = '\0';
    syscall1(SYS_close, fd);
    return total;
}

static long write_file(const char *path, const char *data, int append)
{
    long flags = O_WRONLY | O_CREAT | (append ? O_APPEND : O_TRUNC);
    long fd = syscall4(SYS_openat, AT_FDCWD, (long)path, flags, 0644);
    long n;

    if (fd < 0) {
        return fd;
    }
    n = syscall3(SYS_write, fd, (long)data, strlen(data));
    syscall1(SYS_close, fd);
    return n;
}

static void append_line(char *out, unsigned long cap, const char *line)
{
    unsigned long len = strlen(out);
    unsigned long add = strlen(line);

    if (len + add + 2 >= cap) {
        return;
    }
    memcpy_local(out + len, line, add);
    out[len + add] = '\n';
    out[len + add + 1] = '\0';
}

