static void join_path(const char *dir, const char *name, char *out,
                      unsigned long cap)
{
    unsigned long i = 0;
    unsigned long j = 0;

    if (cap == 0) {
        return;
    }
    if (dir != 0 && dir[0] != '\0' && strcmp(dir, ".") != 0) {
        while (dir[i] != '\0' && i + 1 < cap) {
            out[i] = dir[i];
            i++;
        }
        if (i > 0 && out[i - 1] != '/' && i + 1 < cap) {
            out[i++] = '/';
        }
    }
    while (name[j] != '\0' && i + 1 < cap) {
        out[i++] = name[j++];
    }
    out[i] = '\0';
}

static void split_parent_leaf(const char *path, char *parent,
                              unsigned long parent_cap, char *leaf,
                              unsigned long leaf_cap)
{
    unsigned long slash = 0;
    unsigned long i;

    for (i = 0; path[i] != '\0'; i++) {
        if (path[i] == '/') {
            slash = i + 1;
        }
    }
    if (slash == 0) {
        copy_cstr(parent, "/", parent_cap);
        copy_cstr(leaf, path, leaf_cap);
        return;
    }
    for (i = 0; i + 1 < parent_cap && i + 1 < slash; i++) {
        parent[i] = path[i];
    }
    parent[i] = '\0';
    copy_cstr(leaf, path + slash, leaf_cap);
}

static void sort_lines(char lines[][128], int count)
{
    int i;
    int j;

    for (i = 0; i < count; i++) {
        for (j = i + 1; j < count; j++) {
            if (strcmp(lines[i], lines[j]) > 0) {
                char tmp[128];
                copy_cstr(tmp, lines[i], sizeof(tmp));
                copy_cstr(lines[i], lines[j], 128);
                copy_cstr(lines[j], tmp, 128);
            }
        }
    }
}

static int text_to_lines(const char *in, char lines[][128], int max_lines)
{
    int count = 0;
    unsigned long i = 0;

    while (in[i] != '\0' && count < max_lines) {
        unsigned long j = 0;
        while (in[i] != '\0' && in[i] != '\n' && j + 1 < 128) {
            lines[count][j++] = in[i++];
        }
        lines[count][j] = '\0';
        while (in[i] == '\n') {
            i++;
        }
        count++;
    }
    return count;
}

static void run_filter(char *cmd, const char *input, char *output, unsigned long cap)
{
    char tmp[MAX_LINE];
    char *argv[MAX_ARGS];
    int argc;
    char lines[64][128];
    int count;
    int i;

    output[0] = '\0';
    copy_cstr(tmp, cmd, sizeof(tmp));
    trim(tmp);
    argc = split_words(tmp, argv, MAX_ARGS);
    if (argc == 0) {
        copy_cstr(output, input, cap);
        return;
    }

    if ((strcmp(argv[0], "./busybox") == 0 || strcmp(argv[0], "busybox") == 0) &&
        argc > 1) {
        int j;

        for (j = 0; j < argc; j++) {
            argv[j] = argv[j + 1];
        }
        argc--;
    }

    if (strcmp(argv[0], "grep") == 0 && argc >= 2) {
        char pattern[64];
        int only = argc >= 3 && strcmp(argv[1], "-o") == 0;

        int only = argc >= 3 && strcmp(argv[1], "-o") == 0;

        copy_cstr(pattern, only ? argv[2] : argv[1], sizeof(pattern));
        strip_quotes(pattern);
        count = text_to_lines(input, lines, 64);
        for (i = 0; i < count; i++) {
            if (only && strstr_simple(pattern, "[[:digit:]]")) {
                char match[96];
                unsigned long p = 0;
                unsigned long m = 0;
                int allow_dot = strstr_simple(pattern, ".") != 0;
                char prefix[48];
                unsigned long prefix_len = 0;

                while (pattern[prefix_len] != '\0' &&
                       !starts_with(pattern + prefix_len, "[[:digit:]]") &&
                       prefix_len + 1 < sizeof(prefix)) {
                    prefix[prefix_len] = pattern[prefix_len];
                    prefix_len++;
                }
                prefix[prefix_len] = '\0';

                if (prefix_len > 0) {
                    char *where = lines[i];

                    while (*where != '\0' && !starts_with(where, prefix)) {
                        where++;
                    }
                    if (*where == '\0') {
                        continue;
                    }
                    while (m + 1 < sizeof(match) && m < prefix_len) {
                        match[m] = prefix[m];
                        m++;
                    }
                    p = (unsigned long)(where - lines[i]) + prefix_len;
                } else {
                    while (lines[i][p] != '\0' &&
                           (lines[i][p] < '0' || lines[i][p] > '9')) {
                        p++;
                    }
                }

                while (lines[i][p] >= '0' && lines[i][p] <= '9' &&
                       m + 1 < sizeof(match)) {
                    match[m++] = lines[i][p++];
                }
                if (allow_dot && lines[i][p] == '.' && m + 1 < sizeof(match)) {
                    match[m++] = lines[i][p++];
                    while (lines[i][p] >= '0' && lines[i][p] <= '9' &&
                           m + 1 < sizeof(match)) {
                        match[m++] = lines[i][p++];
                    }
                }
                if (prefix_len > 0 && lines[i][p] == '|' && m + 1 < sizeof(match)) {
                    match[m++] = '|';
                }
                if (m > prefix_len || (prefix_len == 0 && m > 0)) {
                    match[m] = '\0';
                    append_line(output, cap, match);
                }
            } else if (starts_with(lines[i], pattern) || strstr_simple(lines[i], pattern)) {
                append_line(output, cap, lines[i]);
            }
        }
        return;
    }

    count = text_to_lines(input, lines, 64);
    if (strcmp(argv[0], "sort") == 0) {
        sort_lines(lines, count);
        for (i = 0; i < count; i++) {
            append_line(output, cap, lines[i]);
        }
        return;
    }
    if (strcmp(argv[0], "uniq") == 0) {
        for (i = 0; i < count; i++) {
            if (!line_seen(lines, i, lines[i])) {
                append_line(output, cap, lines[i]);
            }
        }
        return;
    }
    if (strcmp(argv[0], "cat") == 0) {
        copy_cstr(output, input, cap);
        return;
    }
    if (strcmp(argv[0], "tail") == 0 && argc >= 2 && strcmp(argv[1], "-n1") == 0) {
        if (count > 0) {
            append_line(output, cap, lines[count - 1]);
        }
        return;
    }
    if (strcmp(argv[0], "awk") == 0) {
        char *prefix_start = cmd;
        char prefix[96];
        unsigned long j = 0;

        while (*prefix_start != '\0' && !starts_with(prefix_start, "print \"")) {
            prefix_start++;
        }
        if (*prefix_start != '\0') {
            prefix_start += 7;
            while (prefix_start[j] != '\0' && prefix_start[j] != '"' &&
                   j + 1 < sizeof(prefix)) {
                prefix[j] = prefix_start[j];
                j++;
            }
            prefix[j] = '\0';
            for (i = 0; i < count; i++) {
                char line[128];

                copy_cstr(line, prefix, sizeof(line));
                copy_cstr(line + strlen(line), lines[i],
                          sizeof(line) - strlen(line));
                append_line(output, cap, line);
            }
            return;
        }
    }

    copy_cstr(output, input, cap);
}

static int strstr_simple(const char *s, const char *needle)
{
    unsigned long i;
    unsigned long n = strlen(needle);

    if (n == 0) {
        return 1;
    }
    for (i = 0; s[i] != '\0'; i++) {
        unsigned long j = 0;
        while (j < n && s[i + j] == needle[j]) {
            j++;
        }
        if (j == n) {
            return 1;
        }
    }
    return 0;
}

static long exec_external(char *line, int background)
{
    char tmp[MAX_LINE];
    char *argv[MAX_ARGS];
    const char *envp[8];
    long pid;
    int status = 0;
    int argc;

    copy_cstr(tmp, line, sizeof(tmp));
    argc = split_words(tmp, argv, MAX_ARGS);
    argc = prepare_exec_args(argv, argc, envp, 8);
    if (argc == 0) {
        return 0;
    }

    pid = syscall6(SYS_clone, 17, 0, 0, 0, 0, 0);
    if (pid == 0) {
        syscall3(SYS_execve, (long)argv[0], (long)argv, (long)envp);
        syscall1(SYS_exit, 127);
    }
    if (pid > 0 && !background) {
        syscall4(SYS_wait4, pid, (long)&status, 0, 0);
        return (status >> 8) & 0xff;
    }
    return pid;
}

static long exec_external_capture(char *line, char *output, unsigned long cap)
{
    char tmp[MAX_LINE];
    char *argv[MAX_ARGS];
    const char *envp[8];
    int fds[2];
    long pid;
    long total = 0;
    int status = 0;
    int argc;

    output[0] = '\0';
    copy_cstr(tmp, line, sizeof(tmp));
    argc = split_words(tmp, argv, MAX_ARGS);
    argc = prepare_exec_args(argv, argc, envp, 8);
    if (argc == 0 || syscall2(SYS_pipe2, (long)fds, O_NONBLOCK) < 0) {
        return -1;
    }

    pid = syscall6(SYS_clone, 17, 0, 0, 0, 0, 0);
    if (pid == 0) {
        syscall1(SYS_close, fds[0]);
        syscall3(SYS_dup3, fds[1], 1, 0);
        syscall3(SYS_dup3, fds[1], 2, 0);
        syscall1(SYS_close, fds[1]);
        syscall3(SYS_execve, (long)argv[0], (long)argv, (long)envp);
        syscall1(SYS_exit, 127);
    }
    syscall1(SYS_close, fds[1]);
    while ((unsigned long)total + 1 < cap) {
        long want = (long)(cap - (unsigned long)total - 1);
        long n;

        if (want > 256) {
            want = 256;
        }
        n = syscall3(SYS_read, fds[0], (long)(output + total), want);
        if (n > 0) {
            total += n;
            continue;
        }
        if (n == 0) {
            break;
        }
        if (n == -11) {
            syscall1(SYS_sched_yield, 0);
            continue;
        }
        break;
    }
    output[total] = '\0';
    syscall1(SYS_close, fds[0]);
    if (pid > 0) {
        syscall4(SYS_wait4, pid, (long)&status, 0, 0);
    }
    return (status >> 8) & 0xff;
}

