static void run_pipeline(char *line)
{
    char stage[MAX_LINE];
    char input[MAX_TEXT];
    char output[MAX_TEXT];
    char *p = line;
    int first = 1;

    input[0] = '\0';
    while (*p != '\0') {
        unsigned long i = 0;
        char quote = 0;

        while (*p != '\0' && i + 1 < sizeof(stage)) {
            if (quote != 0) {
                if (*p == quote) {
                    quote = 0;
                }
            } else if (*p == '\'' || *p == '"') {
                quote = *p;
            } else if (*p == '|') {
                break;
            }
            stage[i++] = *p++;
        }
        stage[i] = '\0';
        if (*p == '|') {
            p++;
        }
        trim(stage);
        if (stage[0] == '\0') {
            continue;
        }

        if (first) {
            first = 0;
            if (starts_with(stage, "cat ")) {
                read_all(stage + 4, input, sizeof(input));
            } else if (starts_with(stage, "echo ")) {
                copy_cstr(input, stage + 5, sizeof(input));
                strip_quotes(input);
                append_line(input, sizeof(input), "");
            } else {
                exec_external_capture(stage, input, sizeof(input));
            }
            continue;
        }

        run_filter(stage, input, output, sizeof(output));
        copy_cstr(input, output, sizeof(input));
    }

    if (!first) {
        print(input);
    }
}

static void run_echo(char *line)
{
