    redir = p;
    while (*redir != '\0') {
        if (redir[0] == '>' && redir[1] == '>') {
            append = 1;
            break;
        }
        if (redir[0] == '>') {
            append = 0;
            break;
        }
        redir++;
    }

    if (*redir == '>') {
        char *path = redir + (append ? 2 : 1);
        *redir = '\0';
        copy_cstr(text, p, sizeof(text));
        trim(text);
        strip_quotes(text);
        while (*path == ' ' || *path == '\t') {
            path++;
        }
        {
            unsigned long len = strlen(text);
            if (len + 2 < sizeof(text)) {
                text[len] = '\n';
                text[len + 1] = '\0';
            }
        }
        write_file(path, text, append);
        return;
    }

    copy_cstr(text, p, sizeof(text));
    trim(text);
    strip_quotes(text);
    print(text);
    print("\n");
}

