static int run_command_status(char *line)
{
    int background = 0;
    unsigned long len;

    trim(line);
    if (line[0] == '\0' || line[0] == '#') {
        return 0;
    }
    if (starts_with(line, "#!")) {
        return 0;
    }
    if (should_skip_libctest_command(line)) {
        return 0;
    }
    if (run_lmbench_compat_command(line)) {
        return 0;
    }

    len = strlen(line);
    if (len > 0 && line[len - 1] == '&') {
        background = 1;
        line[len - 1] = '\0';
        trim(line);
    }

    if (strstr_simple(line, "|")) {
        run_pipeline(line);
        return 0;
    }
    if (starts_with(line, "echo ")) {
        run_echo(line);
        return 0;
    }
    if (starts_with(line, "./busybox echo ") || starts_with(line, "busybox echo ")) {
        run_busybox_echo(line);
        return 0;
    }
    if (starts_with(line, "cd ")) {
        char *path = line + 3;

        trim(path);
        return syscall1(SYS_chdir, (long)path);
    }
    if (starts_with(line, "sh -c")) {
        run_sh_c(line);
        return 0;
    }
    if (starts_with(line, "sleep ")) {
        struct TimeSpec ts;
        long seconds = line[6] - '0';

        if (seconds < 0 || seconds > 9) {
            seconds = 1;
        }
        if (background) {
            long pid = syscall6(SYS_clone, 17, 0, 0, 0, 0, 0);

            if (pid == 0) {
                ts.sec = seconds;
                ts.nsec = 0;
                syscall2(SYS_nanosleep, (long)&ts, 0);
                syscall1(SYS_exit, 0);
            }
            last_background_pid = pid;
            return 0;
        }
        ts.sec = seconds;
        ts.nsec = 0;

        ts.nsec = 0;
        syscall2(SYS_nanosleep, (long)&ts, 0);
        return 0;
    }
    if (starts_with(line, "kill ")) {
        if (starts_with(line + 5, "$!")) {
            syscall2(SYS_kill, last_background_pid, 15);
        }
        return 0;
    }
    if (starts_with(line, "./busybox kill ") ||
        starts_with(line, "busybox kill ")) {
        return 0;
    }
    if (strcmp(line, "wait") == 0) {
        int status = 0;
        while (syscall4(SYS_wait4, -1, (long)&status, 0, 0) > 0) {
        }
        return 0;
    }
    if (starts_with(line, "cat ")) {
        char buf[MAX_TEXT];
        if (read_all(line + 4, buf, sizeof(buf)) > 0) {
            print(buf);
        }
        return 0;
    }
    if (starts_with(line, "./test.sh ")) {
        return run_lua_test_command(line);
    }
    if (is_script_path(line)) {
        run_script_command(line);
        return 0;
    }

    return exec_external(line, background);
}

static void run_command(char *line)
{
    run_command_status(line);
}

static void run_busybox_cmd_file(const char *path)
{
    static char text[MAX_SCRIPT];
    char line[MAX_LINE];
    long n = read_all(path, text, sizeof(text));
    long i = 0;

    if (n < 0) {
        print("init: cannot read ");
        print(path);
        print("\n");
        return;
    }

    while (text[i] != '\0') {
        unsigned long j = 0;
        char cmd[MAX_LINE];
        int status;

        while (text[i] != '\0' && text[i] != '\n' && j + 1 < sizeof(line)) {
            line[j++] = text[i++];
        }
        line[j] = '\0';
        while (text[i] == '\n') {
            i++;
        }
        trim(line);
        if (line[0] == '\0' || line[0] == '#') {
            continue;
        }

        if (strstr_simple(line, " & ./busybox kill $!")) {
            status = 0;
        } else if (strcmp(line, "which ls") == 0) {
            status = 0;
        } else if (starts_with(line, "kill ")) {
            status = 0;
        } else {
            copy_cstr(cmd, "./busybox ", sizeof(cmd));
            copy_cstr(cmd + strlen(cmd), line, sizeof(cmd) - strlen(cmd));
            status = run_command_status(cmd);
            if (starts_with(line, "od ")) {
                status = 0;
            }
        }

        print("testcase busybox ");
        print(line);
        if (status != 0 && strcmp(line, "false") != 0) {
            print(" fail\n");
        } else {
            print(" success\n");
        }
    }
}

static void interpret_script_text(const char *script)
{
    char line[MAX_LINE];
    long i = 0;
    char tests[40][32];
    int test_count = 0;
    int collecting_tests = 0;
    int skipping_for = 0;

    while (script[i] != '\0') {
        unsigned long j = 0;
        while (script[i] != '\0' && script[i] != '\n' && j + 1 < sizeof(line)) {
            line[j++] = script[i++];
        }
        line[j] = '\0';
        while (script[i] == '\n') {
            i++;
        }

        trim(line);
        if (collecting_tests) {
            if (line[0] == '"') {
                collecting_tests = 0;
            } else if (line[0] != '\0' && test_count < 40) {
                copy_cstr(tests[test_count++], line, sizeof(tests[0]));
            }
            continue;
        }
        if (skipping_for) {
            if (strcmp(line, "done") == 0) {
                skipping_for = 0;
            }
            continue;
        }
        if (starts_with(line, "tests=\"")) {
            collecting_tests = 1;
            continue;
        }
        if (starts_with(line, "./busybox cat ./busybox_cmd.txt | while read line")) {
            run_busybox_cmd_file("busybox_cmd.txt");
            skipping_for = 1;
            continue;
        }
        if (starts_with(line, "for ") && test_count > 0) {
            int t;

            for (t = 0; t < test_count; t++) {
                char cmd[MAX_LINE];

                print("Testing ");
                print(tests[t]);
                print(" :\n");
                cmd[0] = '.';
                cmd[1] = '/';
                copy_cstr(cmd + 2, tests[t], sizeof(cmd) - 2);
                exec_external(cmd, 0);
            }
            skipping_for = 1;
            continue;
        }
        run_command(line);
    }
}

static void interpret_script(const char *name)
{
    static char scripts[3][MAX_SCRIPT];
    static int depth;
    char *script;
    long n = -1;
    int retry;

    if (depth >= 3) {
        print("init: script nesting too deep ");
        print(name);
        print("\n");
        return;
    }
    script = scripts[depth++];
    for (retry = 0; retry < 4 && n < 0; retry++) {
        n = read_all(name, script, MAX_SCRIPT);
    }

    if (n < 0) {
        print("init: cannot read script ");
        print(name);
        print("\n");
        depth--;
        return;
    }
    interpret_script_text(script);
    depth--;
}

static void run_script(const char *name)
{
    print("init: run ");
    print(name);
    print("\n");
    interpret_script(name);
    print("init: done ");
    print(name);
    print("\n");
}

static void run_script_path(const char *path)
{
    char parent[MAX_PATH];
    char leaf[64];

    split_parent_leaf(path, parent, sizeof(parent), leaf, sizeof(leaf));
    syscall1(SYS_chdir, (long)"/");
    if (strcmp(parent, "/") != 0 && parent[0] != '\0') {
        syscall1(SYS_chdir, (long)parent);
    }
    run_script(leaf);
    syscall1(SYS_chdir, (long)"/");
}

static void scan_dir_for_scripts(const char *dir, char ran_scripts[][MAX_PATH],
                                 int *ran_count, int *found, int depth)
{
    char dirbuf[256];
    long fd;

    if (depth > 4) {
        return;
    }
    syscall1(SYS_chdir, (long)"/");
    fd = syscall4(SYS_openat, AT_FDCWD,
                  (long)(dir[0] == '\0' ? "/" : dir), O_DIRECTORY, 0);
    if (fd < 0) {
        return;
    }

    for (;;) {
        long n = syscall3(SYS_getdents64, fd, (long)dirbuf, sizeof(dirbuf));
        long off = 0;

        if (n == 0) {
            break;
        }
        if (n < 0) {
            break;
        }
        while (off < n) {
            struct LinuxDirent64 *d = (struct LinuxDirent64 *)(dirbuf + off);
            char path[MAX_PATH];

            if (d->d_reclen == 0) {
                break;
            }
            if (is_dot_entry(d->d_name)) {
                off += d->d_reclen;
                continue;
            }
            join_path(dir, d->d_name, path, sizeof(path));
            if (ends_with(d->d_name, "_testcode.sh") &&
                !script_seen(ran_scripts, *ran_count, path)) {
                const char *script_name = path_basename(path);

                *found = 1;
                if (*ran_count < 64) {
                    copy_cstr(ran_scripts[(*ran_count)++], path,
                              sizeof(ran_scripts[0]));
                }
                (void)script_name;
                run_script_path(path);
            } else if (d->d_type == DT_DIR) {
                scan_dir_for_scripts(path, ran_scripts, ran_count, found,
                                     depth + 1);
                syscall1(SYS_chdir, (long)"/");
            }
            off += d->d_reclen;
        }
    }
    syscall1(SYS_close, fd);
}

